                tasks={tasks.filter(task => 
                  task.text.toLowerCase().includes(taskSearchQuery.toLowerCase()) ||
                  (task.partNumber && task.partNumber.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.workplace && task.workplace.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.createdBy && task.createdBy.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.inProgressBy && task.inProgressBy.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.missingReason && task.missingReason.toLowerCase().includes(taskSearchQuery.toLowerCase()))
                )} 
                missingReasons={props.missingReasons}
                onToggleTask={props.onToggleTask} 
                onEditTask={props.onEditTask} 
                onDeleteTask={props.onDeleteTask} 
                onToggleMissing={props.onToggleMissing}
                onSetInProgress={props.onSetInProgress}
                onToggleBlock={props.onToggleBlock}
                onMarkAsIncorrect={props.onMarkAsIncorrect}
                onAddNote={props.onAddNote}
                onReleaseTask={props.onReleaseTask}
