                                        onClick={handleRequestBOM}
                                        disabled={bomRequestStatus !== 'idle'}
                                        className={`px-6 py-3 font-bold rounded-lg shadow-md flex items-center justify-center gap-2 transition-all duration-200 hover:scale-[1.01] border ${
                                            bomRequestStatus === 'success' 
                                            ? 'bg-green-600 border-green-500 text-white cursor-default' 
                                            : bomRequestStatus === 'loading'
                                            ? 'bg-yellow-800 border-yellow-700 text-yellow-200 cursor-wait'
                                            : 'bg-yellow-700 hover:bg-yellow-600 border-yellow-500 text-white'
                                        }`}
                                    >
                                        {bomRequestStatus === 'loading' ? (
                                                <span>{t('report_btn_loading')}</span>
                                        ) : bomRequestStatus === 'success' ? (
                                                <span>{t('report_btn_success')}</span>
                                        ) : (
                                            <>
                                                <PlusIcon className="w-5 h-5 text-yellow-200" />
                                                <span>{t('bom_request_btn')}</span>
                                            </>
                                        )}
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>
          )}

          {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
            <AnalyticsTab 
                tasks={tasks} 
                onFetchArchivedTasks={props.onFetchArchivedTasks}
                systemBreaks={props.systemBreaks} 
            />
          )}

          {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
              <MissingItemsTab 
                  tasks={tasks} 
                  onDeleteMissingItem={props.onDeleteMissingItem}
                  hasPermission={hasPermission}
              />
          )}

          {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
            <SettingsTab 
              currentUserRole={currentUserRole}
              users={props.users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser}
              parts={props.parts} workplaces={props.workplaces} missingReasons={props.missingReasons}
              onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts}
              onAddWorkplace={props.onAddWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces}
              onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason}
              partRequests={props.partRequests} onApprovePartRequest={props.onApprovePartRequest} onRejectPartRequest={props.onRejectPartRequest}
              onArchiveTasks={props.onArchiveTasks}
              breakSchedules={props.breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule}
              bomItems={props.bomItems} bomRequests={props.bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={props.onApproveBOMRequest} onRejectBOMRequest={props.onRejectBOMRequest}
              roles={props.roles} permissions={props.permissions} onAddRole={props.onAddRole} onDeleteRole={props.onDeleteRole} onUpdatePermission={props.onUpdatePermission}
              installPrompt={installPrompt} onInstallApp={onInstallApp}
            />
          )}

          {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                <PermissionsTab 
                    roles={props.roles} 
                    permissions={props.permissions} 
                    onAddRole={props.onAddRole} 
                    onDeleteRole={props.onDeleteRole} 
                    onUpdatePermission={props.onUpdatePermission}
                />
            )}
        </div>
      </div>
    </div>
  );
};

