);

const ReturnIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" /></svg>
);

const BanIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" className={className} fill="none">
        <circle cx="12" cy="12" r="10" stroke="#DC2626" strokeWidth="2.5" fill="none" />
        <path d="M5 19L19 5" stroke="#DC2626" strokeWidth="2.5" strokeLinecap="round" />
    </svg>
);

// New Truck Icon for Logistics
const TruckIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 24 24" fill="currentColor">
        <path d="M20 8h-3V4H3v14h1v2a2 2 0 0 0 2 2 2 2 0 0 0 2-2v-2h8v2a2 2 0 0 0 2 2 2 2 0 0 0 2-2v-2h1V8zm-2 2v3h-3v-3h3zM5 18H4V6h11v12H5zm13 0h-1v-2h-3v-2h4v4z"/>
    </svg>
);

const TaskList: React.FC<TaskListProps> = (props) => {
    const { t, language } = useLanguage();

    // Edit Priority Mode State (Modal)
    const [priorityEditId, setPriorityEditId] = useState<string | null>(null);

    // Missing Reason Modal State
    const [missingId, setMissingId] = useState<string | null>(null);

    // Note Modal State
    const [noteId, setNoteId] = useState<string | null>(null);
    const [noteVal, setNoteVal] = useState('');

    // Delete Confirmation State
    const [deleteId, setDeleteId] = useState<string | null>(null);

    // Copy Feedback State
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const openPriorityModal = (task: Task) => {
        setPriorityEditId(task.id);
        setMissingId(null);
        setNoteId(null);
        setDeleteId(null);
    };

    const confirmPriority = (id: string, newPriority: PriorityLevel) => {
        const task = props.tasks.find(t => t.id === id);
        if (task) {
            // Preserve the existing text, only change priority
            props.onEditTask(id, task.text, newPriority);
        }
        setPriorityEditId(null);
    };

    const handleMissingClick = (task: Task, e: React.MouseEvent) => {
        e.stopPropagation(); // Ensure the click doesn't bubble up or conflict

        if (task.isMissing) {
            // Logic to cancel missing status
            // Directly toggle off without confirmation dialog for smoother UX
            props.onToggleMissing(task.id);
        } else {
            // Standard open modal logic to SELECT reason
            setMissingId(missingId === task.id ? null : task.id);
            setPriorityEditId(null);
            setNoteId(null);
            setDeleteId(null);
        }
    };

    const confirmMissing = (id: string, reason: string) => {
        props.onToggleMissing(id, reason);
        setMissingId(null);
    };

    const handleNoteClick = (task: Task) => {
        setNoteId(noteId === task.id ? null : task.id);
        setNoteVal(task.note || '');
        setPriorityEditId(null);
        setMissingId(null);
        setDeleteId(null);
    };

    const saveNote = (id: string) => {
        props.onAddNote(id, noteVal);
        setNoteId(null);
    };

    const handleDeleteClick = (id: string) => {
        setDeleteId(id);
        setPriorityEditId(null);
        setMissingId(null);
        setNoteId(null);
    };

    const confirmDelete = () => {
        if (deleteId) {
            props.onDeleteTask(deleteId);
            setDeleteId(null);
        }
    };

    const handleCopyPart = (id: string, text: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 1500);
        }).catch(err => console.error('Copy failed', err));
    };

    // Helper for declension (skloňovanie)
    const getUnitLabel = (count: number, unit: string) => {
        if (language === 'sk') {
            // Slovak Declension Logic
            // 1 kus, 2-4 kusy, 5+ kusov
            let key = '';
            if (count === 1) key = `unit_${unit}_1`;
            else if (count >= 2 && count <= 4) key = `unit_${unit}_2_4`;
            else key = `unit_${unit}_5`;

            // Fallback if specific translation missing, although we added them
            return t(key as any) || unit;
        } else {
            // English Logic
            // 1 pc, 2+ pcs
            let key = '';
            if (count === 1) key = `unit_${unit}_1`;
            else key = `unit_${unit}_5`; // Using _5 mapping for plural in EN for simplicity as keys match file structure

            return t(key as any) || unit;
        }
    };

    return (
        <div className="flex flex-col space-y-3 pb-20">
            {props.tasks.length === 0 && (
                <div className="text-center py-12 text-gray-500 italic bg-gray-800 rounded-xl border border-gray-700">
                    {t('empty_tasks')}
                </div>
            )}

            {props.tasks.map((task) => {
                const isInventoryMode = task.isBlocked;

                // Determine background style
                let bgClass = "";
                let borderClass = "";
                let textClass = "text-white";

                if (task.isDone) {
                     if (task.status === 'incorrectly_entered') {
                         bgClass = "bg-gray-800 opacity-60";
                         textClass = "text-gray-500 line-through";
                     } else {
                        // Standard gray for all completed tasks (including missing ones)
                        bgClass = "bg-gray-800 opacity-80";
                        textClass = "text-gray-500 line-through";
                     }
                } else {
                    if (isInventoryMode) {
                        // Blocked / Inventory Mode
                        bgClass = "bg-gray-800"; // Dark gray background
                        borderClass = "border-l-4 border-gray-600";
                    } else if (task.isInProgress) {
                        bgClass = "bg-yellow-900/20"; // Changed to soft yellow tint
                        borderClass = "border-l-4 border-yellow-500";
                    } else if (task.isMissing) {
                        // 1. Soft red background for missing items
                        bgClass = "bg-red-900/20";
                        borderClass = "border-l-4 border-red-500";
                    } else if (task.type === 'logistics') {
                        // LOGISTICS MODE: Safety Orange / Amber (Logistics standard)
                        bgClass = "bg-orange-900/10";
                        borderClass = "border-l-4 border-orange-500";
                    } else if (task.priority === 'URGENT') {
                        bgClass = "bg-[#0B1121]";
                        borderClass = "border-l-4 border-red-600";
                    } else {
                        bgClass = "bg-[#0B1121]"; // Deep blue
                        borderClass = "border-l-4 border-blue-900";
                    }
                }

                // Calculate display string for unit
                const qtyNum = parseFloat(task.quantity || '0');
                const unitLabel = task.quantityUnit ? getUnitLabel(qtyNum, task.quantityUnit) : '';

                return (
                    <div key={task.id} className={`group relative flex flex-col sm:flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>

                        {/* =========================================================================================
                            LEFT COLUMN: ALL DATA AND INFORMATION
                           ========================================================================================= */}
                        {/* Reduced spacing gap-1 */}
                        <div className="flex-grow p-4 flex flex-col gap-1 min-w-0 relative">

                            {/* Background Lock Icon for Inventory Mode */}
                            {isInventoryMode && !task.isDone && (
                                <div className="absolute left-2 top-1/2 -translate-y-1/2 z-0 pointer-events-none opacity-20">
                                    <LockIcon className="w-24 h-24 text-gray-400" />
                                </div>
                            )}

                            {/* Background Truck Icon for Logistics Mode */}
                            {task.type === 'logistics' && !task.isDone && !isInventoryMode && (
                                <div className="absolute left-2 top-1/2 -translate-y-1/2 z-0 pointer-events-none opacity-20">
                                    <TruckIcon className="w-24 h-24 text-orange-500/20" />
                                </div>
                            )}

                            {/* Relative z-10 wrapper to keep content above the background icon */}
                            <div className="relative z-10">

                                {/* Incorrect Banner - Static */}
                                {task.status === 'incorrectly_entered' && (
                                    <div className="flex mb-1">
                                        <span className="inline-flex items-center gap-2 px-3 py-1 bg-red-900/40 text-red-200 text-sm font-bold uppercase rounded shadow-sm border border-red-800">
                                            <BanIcon className="w-4 h-4" /> 
                                            {language === 'sk' ? 'Chybne zadaná úloha' : t('status_incorrect')}
                                        </span>
                                    </div>
                                )}

                                {/* Inventory Mode Banner */}
                                {isInventoryMode && !task.isDone && (
                                    <div className="flex mb-1">
                                        <span className="inline-flex items-center gap-2 px-3 py-1 bg-gray-700 text-white text-sm font-bold uppercase rounded animate-pulse shadow-sm border border-gray-600">
                                            INVENTÚRA
                                        </span>
                                    </div>
                                )}

                                {/* Logistics Mode Banner */}
                                {task.type === 'logistics' && !task.isDone && !isInventoryMode && (
                                    <div className="flex mb-1">
                                        <span className="inline-flex items-center gap-2 px-3 py-1 bg-orange-900/40 text-orange-200 text-sm font-bold uppercase rounded animate-pulse shadow-sm border border-orange-500">
                                            <TruckIcon className="w-4 h-4" /> {t('status_logistics')}
                                        </span>
                                    </div>
                                )}

                                {/* 2. Missing Message: White text, red background, blinking, above part number */}
                                {task.isMissing && !isInventoryMode && (
                                    <div className="flex mb-1">
                                        <span className="inline-flex items-center gap-2 px-3 py-1 bg-red-600 text-white text-sm font-bold uppercase rounded animate-pulse shadow-sm">
                                            <ExclamationIcon className="w-4 h-4" /> {task.missingReason}
                                        </span>
                                    </div>
                                )}

                                {/* ROW 1: Part Number (Left) vs Quantity Group (Right) */}
                                <div className="flex justify-between items-start gap-3">
                                    <h3 className={`text-2xl sm:text-3xl font-bold truncate leading-tight ${textClass}`}>
                                        {task.partNumber || task.text}
                                    </h3>

                                    <div className="flex flex-col items-end flex-shrink-0">
                                        {/* Capsule for Quantity - Inherit text color, same font size for unit */}
                                        <span className={`bg-black border border-gray-700 shadow-inner px-3 py-1 rounded-full text-xl font-bold ${textClass}`}>
                                            {task.quantity || "-"} 
                                            <span className="ml-1 text-lg font-normal">
                                                {unitLabel}
                                            </span>
                                        </span>
                                        {/* Creator Info under Quantity */}
                                        <div className="text-xs text-gray-400 mt-1 font-mono text-right">
                                            <span className="font-bold text-gray-500">{task.createdBy}</span> • {new Date(task.createdAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                                        </div>
                                    </div>
                                </div>

                                {/* ROW 2: Workplace + Note + Completed Info */}
                                <div className="flex flex-wrap gap-2 items-center">
                                    {/* Workplace */}
                                    <span className={`text-lg font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : 'text-cyan-400'}`}>
                                        {task.workplace || "---"}
                                    </span>

                                    {/* Note (Pastel Yellow) */}
                                    {task.note && (
                                        <span 
                                            className="inline-block px-2 py-0.5 rounded bg-[#fef9c3] text-gray-800 text-xs font-bold shadow-sm border border-yellow-200 leading-tight" 
                                            title={task.note}
                                        >
                                            {task.note}
                                        </span>
                                    )}

                                    {/* Completed Status */}
                                    {task.isDone && !task.isMissing && (
                                        <span className="text-green-500 flex items-center gap-1 text-xs font-mono border border-green-600/30 bg-green-900/20 px-2 py-0.5 rounded">
                                            <CheckIcon className="w-3 h-3" /> {task.completedBy} • {task.completedAt ? new Date(task.completedAt).toLocaleTimeString() : ''}
                                        </span>
                                    )}
                                </div>

                                {/* ROW 3: Resolving Status (Under Workplace) */}
                                {task.isInProgress && (
                                    <div className="flex">
                                        <span className="text-yellow-400 text-xs font-bold uppercase tracking-wide border border-yellow-600/50 bg-yellow-900/30 px-2 py-0.5 rounded">
                                            {t('status_resolving')} {task.inProgressBy}
                                        </span>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* =========================================================================================
                            RIGHT COLUMN: ALL BUTTONS (Actions)
                            5. Removed separator lines (borders)
                           ========================================================================================= */}
                        <div className="flex flex-shrink-0 items-center justify-center p-3">
                            {/* 4. Grid cols 5 to wrap buttons into two rows if > 5 */}
                            <div className="grid grid-cols-5 gap-2 items-center justify-center">

                                {!task.isDone ? (
                                    <>
                                        {/* Row 1: Utility Buttons - Reordered */}

                                        {/* 1. Resolve - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_resolve') && (
                                            <button onClick={() => props.onSetInProgress(task.id)} className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isInProgress ? 'bg-yellow-600 text-white border border-yellow-500' : 'bg-gray-700 text-yellow-500 hover:bg-gray-600 border border-gray-600'}`} title={t('status_resolving')}>
                                                {task.isInProgress ? <PauseIcon className="w-10 h-10" /> : <PlayIcon className="w-10 h-10" />}
                                            </button>
                                        )}

                                        {/* 2. Copy - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_copy') && (
                                            <button 
                                                onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                className={`w-16 h-16 flex items-center justify-center rounded-lg transition-all active:scale-95 shadow-lg border ${
                                                    copiedId === task.id 
                                                    ? 'bg-green-600 border-green-500 text-white' 
                                                    : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                }`} 
                                                title={t('btn_copy')}
                                            >
                                                {copiedId === task.id ? <span className="font-bold text-xs">OK</span> : <CopyIcon className="w-8 h-8" />}
                                            </button>
                                        )}

                                        {/* 3. Missing - Red with white icon - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_missing') && (
                                            <button 
                                                onClick={(e) => handleMissingClick(task, e)} 
                                                className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${task.isMissing ? 'bg-red-800 text-white border-red-500' : 'bg-red-600 text-white hover:bg-red-500 border-red-500'}`} 
                                                title={t('perm_btn_missing')}
                                            >
                                                <ExclamationIcon className="w-10 h-10" />
                                            </button>
                                        )}

                                        {/* 4. Lock / Inventory - ALWAYS VISIBLE if permission exists */}
                                        {props.hasPermission('perm_btn_lock') && (
                                            <button onClick={() => props.onToggleBlock(task.id)} className={`w-16 h-16 flex items-center justify-center rounded-lg transition-all active:scale-95 shadow-lg ${task.isBlocked ? 'bg-gray-600 text-white border border-gray-500' : 'bg-gray-700 text-gray-400 hover:bg-gray-600 border border-gray-600'}`} title={t('perm_btn_lock')}>
                                                <LockIcon className="w-8 h-8" />
                                            </button>
                                        )}

                                        {/* 5. Finish - Pea Green - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_finish') && (
                                            <button onClick={() => props.onToggleTask(task.id)} className="w-16 h-16 flex items-center justify-center rounded-xl bg-lime-600 text-white hover:bg-lime-500 transition-all active:scale-95 shadow-xl border border-lime-500" title={t('btn_finish')}>
                                                <CheckIcon className="w-12 h-12" />
                                            </button>
                                        )}

                                        {/* 6. Priority - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_edit') && (
                                            <button onClick={() => openPriorityModal(task)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-gray-700 text-blue-400 border border-gray-600 hover:bg-gray-600 hover:text-white transition-colors" title="Zmeniť prioritu">
                                                <SignalIcon className="w-8 h-8" />
                                            </button>
                                        )}

                                        {/* 7. Note - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_note') && (
                                            <button onClick={() => handleNoteClick(task)} className={`w-16 h-16 flex items-center justify-center rounded-lg border transition-colors ${task.note ? 'bg-[#fef9c3] text-gray-800 border-yellow-200' : 'bg-gray-700 text-gray-300 border-gray-600 hover:bg-gray-600'}`} title={t('btn_note')}>
                                                <ChatIcon className="w-8 h-8" />
                                            </button>
                                        )}

                                        {/* 8. Incorrect - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_incorrect') && task.status !== 'incorrectly_entered' && (
                                            <button 
                                                onClick={() => props.onMarkAsIncorrect(task.id)} 
                                                className="w-16 h-16 flex items-center justify-center rounded-xl bg-white transition-all active:scale-95 shadow-lg border-2 border-gray-300 hover:border-red-500 overflow-hidden" 
                                                title={t('btn_mark_incorrect')}
                                            >
                                                <BanIcon className="w-10 h-10" />
                                            </button>
                                        )}

                                        {/* 9. Delete - Hidden if Blocked */}
                                        {!isInventoryMode && props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => handleDeleteClick(task.id)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors" title={t('perm_btn_delete')}>
                                                <TrashIcon className="w-8 h-8" />
                                            </button>
                                        )}
                                    </>
                                ) : (
                                    /* Done Actions */
                                    <>
                                        {props.hasPermission('perm_btn_copy') && (
                                            <button 
                                                onClick={() => handleCopyPart(task.id, task.partNumber || '')} 
                                                className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${
                                                    copiedId === task.id 
                                                    ? 'bg-green-600 border-green-500 text-white' 
                                                    : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'
                                                }`} 
                                                title={t('btn_copy')}
                                            >
                                                {copiedId === task.id ? <span className="font-bold text-xs">OK</span> : <CopyIcon className="w-8 h-8" />}
                                            </button>
                                        )}
                                        {props.hasPermission('perm_btn_return') && (
                                            <button 
                                                onClick={() => props.onToggleTask(task.id)} 
                                                className="w-16 h-16 flex items-center justify-center rounded-xl bg-orange-600 hover:bg-orange-500 text-white shadow-md transition-all active:scale-95 border border-orange-500" 
                                                title={t('btn_stop')}
                                            >
                                                <ReturnIcon className="w-10 h-10" />
                                            </button>
                                        )}
                                        {props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => handleDeleteClick(task.id)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors" title={t('perm_btn_delete')}>
                                                <TrashIcon className="w-8 h-8" />
                                            </button>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                );
            })}

            {/* Global Modal for Priority Edit */}
            {priorityEditId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setPriorityEditId(null)}>
                    <div className="bg-gray-800 border-2 border-blue-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-blue-400 mb-6 text-center uppercase tracking-wide">{t('priority_label')}</h3>
                        <div className="grid grid-cols-1 gap-3">
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'LOW')} 
                                className="p-4 bg-slate-700 hover:bg-slate-600 border border-slate-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_low')}
                            </button>
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'NORMAL')} 
                                className="p-4 bg-green-700 hover:bg-green-600 border border-green-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_normal')}
                            </button>
                            <button 
                                onClick={() => confirmPriority(priorityEditId, 'URGENT')} 
                                className="p-4 bg-red-700 hover:bg-red-600 border border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase"
                            >
                                {t('prio_urgent')}
                            </button>
                        </div>
                        <button 
                            onClick={() => setPriorityEditId(null)} 
                            className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                        >
                            {t('btn_cancel')}
                        </button>
                    </div>
                </div>,
                document.body
            )}

            {/* Global Modal for Missing Reason - Rendered via Portal to escape transforms */}
            {missingId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setMissingId(null)}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-red-400 mb-6 text-center uppercase tracking-wide">{t('modal_missing_title')}</h3>
                        <div className="grid grid-cols-1 gap-3">
                            {props.missingReasons.map(r => (
                                <button 
                                    key={r.id} 
                                    onClick={() => confirmMissing(missingId, r.value)} 
                                    className="p-4 bg-gray-700 hover:bg-red-900/30 border border-gray-600 hover:border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1"
                                >
                                    {r.value}
                                </button>
                            ))}
                        </div>
                        <button 
                            onClick={() => setMissingId(null)} 
                            className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                        >
                            {t('btn_cancel')}
                        </button>
                    </div>
                </div>,
                document.body
            )}

            {/* Global Modal for Notes - Rendered via Portal */}
            {noteId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setNoteId(null)}>
                    <div className="bg-gray-800 border-2 border-yellow-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold text-yellow-400 mb-4 text-center uppercase tracking-wide">{t('btn_note')}</h3>
                        <textarea 
                            value={noteVal} 
                            onChange={(e) => setNoteVal(e.target.value)} 
                            className="w-full bg-gray-700 text-white p-3 rounded-lg border border-gray-600 focus:border-yellow-500 outline-none mb-4" 
                            rows={4}
                            autoFocus
                            placeholder={t('btn_note') + "..."}
                        />
                        <div className="flex gap-3">
                            <button onClick={() => saveNote(noteId)} className="flex-1 py-3 bg-yellow-600 hover:bg-yellow-500 text-white rounded-lg font-bold transition-colors">{t('btn_save')}</button>
                            <button onClick={() => setNoteId(null)} className="flex-1 py-3 bg-gray-700 hover:bg-gray-600 text-gray-300 rounded-lg font-bold transition-colors">{t('btn_cancel')}</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

             {/* Global Modal for Delete Confirmation - Rendered via Portal */}
             {deleteId && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setDeleteId(null)}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-6">
                            <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/50">
                                <TrashIcon className="w-8 h-8 text-red-500" />
                            </div>
                            <h3 className="text-xl font-bold text-white mb-2">{t('miss_delete_confirm')}</h3>
                        </div>
                        <div className="flex gap-3">
                             <button 
                                onClick={() => setDeleteId(null)} 
                                className="flex-1 py-3 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={confirmDelete} 
                                className="flex-1 py-3 bg-red-600 text-white rounded-lg hover:bg-red-700 font-bold transition-colors shadow-lg flex items-center justify-center gap-2"
                            >
                                <TrashIcon className="w-5 h-5" />
                                {language === 'sk' ? 'Vymazať' : 'Delete'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default TaskList;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  getDoc,
  where,
  limit,
  setDoc,
  runTransaction
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
  description?: string;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean;
  inventoryHistory?: InventorySession[];
  type?: 'production' | 'logistics'; // NEW FIELD for task type
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); // New state
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- DATA FETCHING ---

  // Users - Realtime (Important for login check)
  useEffect(() => {
    const q = query(collection(db, 'users'));
    return onSnapshot(q, (snapshot) => {
        const fetchedUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserData));
        if (fetchedUsers.length === 0) seedDatabase(); 
        else setUsers(fetchedUsers);
    });
  }, []);

  // Tasks - Realtime (CRITICAL OPTIMIZATION: Empty dependency array)
  useEffect(() => {
    // OPTIMIZATION: In a real app, you might want to limit this query (e.g. limit(500) or where('isDone', '==', false))
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      // Sound Notification Logic - uses checkPermissionRef to avoid re-render loop
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []); // REMOVED dependencies to prevent re-fetching on role change

  // --- SMART CACHING LOGIC ---
  const incrementDataVersion = async () => {
      // Increments the version in Firestore. Call this whenever DB data (parts/wp/bom) changes.
      const metaRef = doc(db, 'metadata', 'system');
      try {
          await runTransaction(db, async (transaction) => {
              const metaDoc = await transaction.get(metaRef);
              if (!metaDoc.exists()) {
                  transaction.set(metaRef, { dataVersion: 1 });
              } else {
                  const newVersion = (metaDoc.data().dataVersion || 0) + 1;
                  transaction.update(metaRef, { dataVersion: newVersion });
              }
          });
      } catch (e) {
          console.error("Version increment failed", e);
      }
  };

  const refreshSmartData = async () => {
      // 1. Get Cloud Version (Cost: 1 Read)
      try {
          const metaRef = doc(db, 'metadata', 'system');
          const metaSnap = await getDoc(metaRef);

          // If metadata doesn't exist (fresh install), treat as version 0 to force fetch
          const serverVersion = metaSnap.exists() ? metaSnap.data().dataVersion : 0;
          const localVersion = parseInt(localStorage.getItem('cached_data_version') || '-1');

          let loadedFromCache = false;

          // 2. Try Cache if versions match
          if (serverVersion === localVersion && localVersion !== -1) {
              try {
                  console.log("📦 Loading static data (Parts, WP, BOM, Logistics Ops) from Cache...");
                  const cParts = localStorage.getItem('cached_parts');
                  const cWp = localStorage.getItem('cached_workplaces');
                  const cReasons = localStorage.getItem('cached_reasons');
                  const cLogOps = localStorage.getItem('cached_log_ops');
                  const cBom = localStorage.getItem('cached_bom');

                  if (cParts && cWp && cReasons && cBom && cLogOps) {
                      setParts(JSON.parse(cParts));
                      setWorkplaces(JSON.parse(cWp));
                      setMissingReasons(JSON.parse(cReasons));
                      setLogisticsOperations(JSON.parse(cLogOps));
                      setBomItems(JSON.parse(cBom));
                      loadedFromCache = true;
                  }
              } catch (err) {
                  console.warn("Cache parsing failed, falling back to cloud.", err);
              }
          }

          if (!loadedFromCache) {
              // --- FETCH FROM CLOUD (Cost: ~N Reads) ---
              console.log(`☁️ Fetching static data from Cloud (v${serverVersion})...`);

              const pSnap = await getDocs(query(collection(db, 'parts'), orderBy('value')));
              const wSnap = await getDocs(query(collection(db, 'workplaces'), orderBy('value')));
              const rSnap = await getDocs(query(collection(db, 'missing_reasons'), orderBy('value')));
              const lSnap = await getDocs(query(collection(db, 'logistics_operations'), orderBy('value')));
              const bSnap = await getDocs(query(collection(db, 'bom_items'), orderBy('parentPart')));

              const newParts = pSnap.docs.map(d => ({id:d.id, ...d.data()} as DBItem));
              const newWorkplaces = wSnap.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem));
              const newReasons = rSnap.docs.map(d => ({id:d.id, value:d.data().value} as DBItem));
              const newLogOps = lSnap.docs.map(d => ({id:d.id, value:d.data().value} as DBItem));
              const newBOM = bSnap.docs.map(d => ({id:d.id, ...d.data()} as BOMItem));

              // Check if logistics operations empty (first run with this feature)
              if (newLogOps.length === 0) {
                  // Seed defaults
                  const defaults = ['VYKLÁDKA', 'NAKLÁDKA', 'ZASKLADNENIE', 'INTERNÝ PRESUN'];
                  const batch = writeBatch(db);
                  defaults.forEach(op => batch.set(doc(collection(db, 'logistics_operations')), { value: op }));
                  await batch.commit();
                  // Re-run refresh or manual set
                  // For simplicity we set manually here to avoid loops
                  setLogisticsOperations(defaults.map((v, i) => ({ id: `default-${i}`, value: v })));
              } else {
                  setLogisticsOperations(newLogOps);
              }

              // Save to State
              setParts(newParts);
              setWorkplaces(newWorkplaces);
              setMissingReasons(newReasons);
              setBomItems(newBOM);
              if(newLogOps.length > 0) setLogisticsOperations(newLogOps); // Already set in block above if empty

              // Save to Cache
              localStorage.setItem('cached_parts', JSON.stringify(newParts));
              localStorage.setItem('cached_workplaces', JSON.stringify(newWorkplaces));
              localStorage.setItem('cached_reasons', JSON.stringify(newReasons));
              localStorage.setItem('cached_log_ops', JSON.stringify(newLogOps.length > 0 ? newLogOps : [{value:'Loading...'}]));
              localStorage.setItem('cached_bom', JSON.stringify(newBOM));
              localStorage.setItem('cached_data_version', serverVersion.toString());
          }
      } catch (e) {
          console.error("Smart Data Load Failed:", e);
      }
  };

  // Initial Fetch using Smart Logic
  useEffect(() => {
      refreshSmartData();
  }, []);

  // Realtime needed for Requests & Breaks & Roles (Admin/Mgmt stuff)
  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'break_schedules')); return onSnapshot(q, s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'notifications')); return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  // System breaks needs to be realtime for calculations
  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  // Roles & Permissions (Keep realtime to update UI instantly)
  useEffect(() => {
      const q = query(collection(db, 'roles'));
      return onSnapshot(q, (snapshot) => {
          const fetchedRoles = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Role));

          const legacyRoles = ['SUPERVISOR', 'LOGISTICIAN'];
          const uniqueRolesMap = new Map<string, Role>();
          const toDeleteIds: string[] = [];

          // 1. Identify duplicates and legacy roles
          fetchedRoles.forEach(role => {
              const name = role.name.toUpperCase();

              if (legacyRoles.includes(name)) {
                  toDeleteIds.push(role.id);
                  return;
              }

              if (uniqueRolesMap.has(name)) {
                  const existing = uniqueRolesMap.get(name)!;
                  // Prefer system roles, or keep the existing one
                  if (existing.isSystem && !role.isSystem) {
                      toDeleteIds.push(role.id);
                  } else if (!existing.isSystem && role.isSystem) {
                      toDeleteIds.push(existing.id);
                      uniqueRolesMap.set(name, role);
                  } else {
                      // Duplicate of same type, delete current
                      toDeleteIds.push(role.id);
                  }
              } else {
                  uniqueRolesMap.set(name, role);
              }
          });

          // 2. Cleanup Duplicates in DB
          if (toDeleteIds.length > 0) {
              const batch = writeBatch(db);
              toDeleteIds.forEach(id => {
                  batch.delete(doc(db, 'roles', id));
              });
              batch.commit().catch(e => console.error("Error cleaning duplicates", e));
          }

          const validRoles = Array.from(uniqueRolesMap.values());

          if (validRoles.length === 0 && fetchedRoles.length === 0) seedRolesAndPermissions();
          else setRoles(validRoles);
      });
  }, []);

  useEffect(() => {
      const q = query(collection(db, 'permissions'));
      return onSnapshot(q, (snapshot) => {
          setPermissions(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Permission)));
      });
  }, []);

  // Break Logic
  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);

  const seedDatabase = async () => {
      await addDoc(collection(db, 'users'), { username: 'USER', password: '123', role: 'USER' });
      await addDoc(collection(db, 'users'), { username: 'ADMIN', password: '321', role: 'ADMIN' });
      // Init Metadata for versioning
      await setDoc(doc(db, 'metadata', 'system'), { dataVersion: 1 });

      const b = writeBatch(db);
      initialParts.forEach(p => b.set(doc(collection(db, 'parts')), { value: p, description: '' }));
      initialWorkplaces.forEach(w => b.set(doc(collection(db, 'workplaces')), { value: w }));
      seedMissingReasons.forEach(r => b.set(doc(collection(db, 'missing_reasons')), { value: r }));
      // Seed default logistics ops
      const logOps = ['VYKLÁDKA', 'NAKLÁDKA', 'ZASKLADNENIE', 'INTERNÝ PRESUN'];
      logOps.forEach(op => b.set(doc(collection(db, 'logistics_operations')), { value: op }));

      await b.commit();
      refreshSmartData(); // Manual refresh after seed
  };

  const seedRolesAndPermissions = async () => {
      const batch = writeBatch(db);
      const roleDefs = [
          { name: 'ADMIN', isSystem: true },
          { name: 'USER', isSystem: true },
          { name: 'LEADER', isSystem: true }
      ];
      const roleMap: Record<string, string> = {};

      for (const r of roleDefs) {
          const ref = doc(db, 'roles', r.name); 
          batch.set(ref, r);
          roleMap[r.name] = ref.id;
      }

      const allPerms = [
          'perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_missing', 'perm_tab_permissions', 'perm_logistics_mode',
          'perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_return', 'perm_btn_lock',
          'perm_view_fullscreen', 'perm_play_sound', 'perm_view_passwords',
          'perm_manage_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'
      ];

      const assign = (role: string, list: string[]) => {
          const rid = roleMap[role];
          if (!rid) return;
          list.forEach(p => batch.set(doc(collection(db, 'permissions')), { roleId: rid, permissionName: p }));
      };

      assign('ADMIN', allPerms);
      assign('USER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_note', 'perm_btn_finish', 'perm_play_sound']);
      assign('LEADER', ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_logistics_mode', 'perm_btn_incorrect', 'perm_btn_edit', 'perm_btn_return', 'perm_play_sound']); 

      await batch.commit();
  };

  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };
  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };
  const handleAddUser = (u: UserData) => addDoc(collection(db, 'users'), u);
  const handleUpdatePassword = (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {password: p}); };
  const handleUpdateUserRole = (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) updateDoc(doc(db,'users', user.id!), {role: r}); };
  const handleDeleteUser = (u: string) => { const user = users.find(us => us.username === u); if(user) deleteDoc(doc(db,'users', user.id!)); };

  // Data Mutation Wrappers (To update versioning)
  const handleAddPart = async (v: string, desc?: string) => { 
      await addDoc(collection(db,'parts'), {value:v, description: desc || ''}); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleBatchAddParts = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(v => {
          const [val, desc] = v.split(';');
          if(val) b.set(doc(collection(db,'parts')), {value:val.trim(), description: desc ? desc.trim() : ''});
      }); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeletePart = async (id: string) => { 
      await deleteDoc(doc(db,'parts',id)); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteAllParts = async () => { 
      const s=await getDocs(collection(db,'parts')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };

  const handleAddWorkplace = async (v: string, t?: number) => { 
      await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleBatchAddWorkplaces = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteWorkplace = async (id: string) => { 
      await deleteDoc(doc(db,'workplaces',id)); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteAllWorkplaces = async () => { 
      const s=await getDocs(collection(db,'workplaces')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };

  const handleAddMissingReason = async (v: string) => { 
      await addDoc(collection(db,'missing_reasons'), {value:v}); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteMissingReason = async (id: string) => { 
      await deleteDoc(doc(db,'missing_reasons',id)); 
      await incrementDataVersion();
      refreshSmartData(); 
  };

  const handleAddLogisticsOperation = async (v: string) => { 
      await addDoc(collection(db,'logistics_operations'), {value:v}); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteLogisticsOperation = async (id: string) => { 
      await deleteDoc(doc(db,'logistics_operations',id)); 
      await incrementDataVersion();
      refreshSmartData(); 
  };

  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = (s:string, e:string) => addDoc(collection(db,'break_schedules'), {start:s, end:e});
  const handleDeleteBreakSchedule = (id: string) => deleteDoc(doc(db,'break_schedules',id));

  const handleAddBOMItem = async (p:string, c:string, q:number) => { 
      await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleBatchAddBOMItems = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteBOMItem = async (id: string) => { 
      await deleteDoc(doc(db,'bom_items',id)); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleDeleteAllBOMItems = async () => { 
      const s=await getDocs(collection(db,'bom_items')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
      await incrementDataVersion();
      refreshSmartData(); 
  };
  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = (n:string) => {
      const nameUpper = n.toUpperCase();
      if (roles.some(r => r.name === nameUpper)) {
          alert("Rola s týmto názvom už existuje!");
          return;
      }
      addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false});
  };
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) deleteDoc(doc(db,'permissions',p.id)); } };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, type: 'production' | 'logistics' = 'production') => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    let finalStandardTime = 0;

    if (type === 'production') {
        const wpObj = workplaces.find(w => w.value === wp);
        finalStandardTime = wpObj?.standardTime || 0;

        // If unit is 'pallet' and quantity is provided, multiply standard time by quantity
        if (unit === 'pallet' && qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) {
                finalStandardTime = Math.round(finalStandardTime * numericQty);
            }
        }
    } else {
        // Logistics tasks currently default to 0 standard time (measured by actual duration)
        // Future enhancement: Add standard times for logistics operations per unit
        finalStandardTime = 0;
    }

    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: finalStandardTime, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser,
        type: type // Save the type
    });
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              isInProgress: false, 
              inProgressBy: null,
              isBlocked: false 
          });
          // Alert Notification
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons} logisticsOperations={logisticsOperations}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          onAddLogisticsOperation={handleAddLogisticsOperation} onDeleteLogisticsOperation={handleDeleteLogisticsOperation}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
        />
      )}
    </div>
  );
};

