    </svg>
);

const BellIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>;
const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const LogoutIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>;
const DownloadIcon: React.FC<{ className?: string }> = ({ className }) => (<svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>);
const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);


const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, onAddTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces
  } = props;

  const { t, language, setLanguage } = useLanguage();

  // Entry Mode: Production vs Logistics
  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');

  const [selectedPart, setSelectedPart] = useState<DBItem | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);

  // Logistics specific
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');

  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'permissions'>('entry');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // BOM Tab specific states
  const [bomParentQuery, setBomParentQuery] = useState('');
  const [bomQuantity, setBomQuantity] = useState('');
  const [bomSelectedWorkplace, setBomSelectedWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());
  const [bomRequestStatus, setBomRequestStatus] = useState<'idle' | 'loading' | 'success'>('idle');

  // New states to control when BOM results are displayed (after explicit calculation)
  const [displayedBomParent, setDisplayedBomParent] = useState<string | null>(null);
  const [displayedBomQuantity, setDisplayedBomQuantity] = useState<number | null>(null);


  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      // Safety: Admin always has access to permissions and settings to avoid lockout
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }

      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const unfinishedTasksCount = tasks.filter(t => !t.isDone).length;
  const pendingRequestsCount = props.partRequests.length + props.bomRequests.length;
  const workplaceStrings = useMemo(() => workplaces.map(w => w.value), [workplaces]);

  // Use DB operations if available, otherwise fallback
  const logisticsOperationsList = useMemo(() => {
      if (props.logisticsOperations && props.logisticsOperations.length > 0) {
          return props.logisticsOperations;
      }
      return [
          { id: 'op_unloading', value: t('op_unloading') },
          { id: 'op_loading', value: t('op_loading') },
          { id: 'op_putaway', value: t('op_putaway') },
          { id: 'op_move', value: t('op_move') }
      ];
  }, [props.logisticsOperations, t]);

  const requestNotificationPermission = async () => {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      if (permission === 'granted') {
        console.log('Push notification permission granted.');
      }
    }
  };

  useEffect(() => {
    requestNotificationPermission();
  }, []);

  const handleSendToTasks = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) {
            alert(t('fill_all_fields')); 
            return;
        }
        onAddTask(selectedPart.value, selectedWorkplace, quantity, quantityUnit, priority, 'production');
    } else {
        // Logistics Mode
        if (!logisticsRef || !logisticsOp || !quantity) {
            alert(t('fill_all_fields'));
            return;
        }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, 'logistics');
    }

    // Reset fields
    setSelectedPart(null);
    setSelectedWorkplace(null);
    setLogisticsRef('');
    setLogisticsOp('');
    setQuantity('');
    // Keep 'boxes' or 'pallet' if selected, default to pcs for production, but handle logic if pcs was disabled
    if (entryMode === 'logistics' && quantityUnit === 'pcs') {
         setQuantityUnit('pallet'); // reset to pallet if pcs was somehow selected
    } else {
         setQuantityUnit('pcs'); 
    }
    setPriority('NORMAL'); 

    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleCreateTaskFromBOM = (childPart: string, requiredQty: number, bomItemId: string) => {
      if (!bomSelectedWorkplace) {
          alert(t('select_bom_workplace')); 
          return;
      }
      const roundedQty = Math.ceil(requiredQty);

      onAddTask(childPart, bomSelectedWorkplace, roundedQty.toString(), 'pcs', 'NORMAL', 'production');

      setClickedBOMTasks(prev => new Set(prev).add(bomItemId));
      setShowSuccessMessage(true);
      setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleCalculateBOM = () => {
    if (!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0) {
        alert(t('bom_invalid_input')); 
        return;
    }
    setDisplayedBomParent(bomParentQuery);
    setDisplayedBomQuantity(parseFloat(bomQuantity));
    setClickedBOMTasks(new Set()); // Reset tasks for new BOM calculation
  };

  const handleRequestBOM = async () => {
      if (displayedBomParent && bomRequestStatus === 'idle') {
          setBomRequestStatus('loading');
          const success = await props.onRequestBOM(displayedBomParent);
          if (success) {
              setBomRequestStatus('success');
              setTimeout(() => setBomRequestStatus('idle'), 3000);
          } else {
              setBomRequestStatus('idle');
          }
      }
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const handleExportTasks = () => {
      if (typeof XLSX === 'undefined') {
          alert('Export library missing.');
          return;
      }
      const data = tasks.map(task => ({
          ID: task.id,
          [t('miss_th_created')]: task.createdAt ? new Date(task.createdAt).toLocaleString('sk-SK') : '-',
          [t('miss_th_part')]: task.partNumber || task.text,
          [t('miss_th_wp')]: task.workplace || '-',
          [t('kpi_quantity')]: task.quantity || '-',
          [t('status_label')]: task.isDone ? t('status_completed') : t('status_open'),
          [t('task_completed_by')]: task.completedBy || '-'
      }));
      const ws = XLSX.utils.json_to_sheet(data);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Tasks");
      XLSX.writeFile(wb, `Tasks_Export_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  // Filter BOM items based on displayed (calculated) states
  const filteredBomItems = useMemo(() => {
    if (!displayedBomParent || !displayedBomQuantity) return [];
    return props.bomItems
        .filter(item => item.parentPart.toLowerCase() === displayedBomParent.toLowerCase());
  }, [props.bomItems, displayedBomParent, displayedBomQuantity]);

  const getRoleBadgeColor = (role: string) => {
    switch (role) {
        case 'ADMIN': return 'bg-red-600 border-red-500 text-white shadow-[0_0_10px_rgba(220,38,38,0.5)]';
        case 'LEADER': return 'bg-blue-600 border-blue-500 text-white shadow-[0_0_10px_rgba(37,99,235,0.5)]';
        default: return 'bg-teal-600 border-teal-500 text-white shadow-[0_0_10px_rgba(13,148,136,0.5)]'; // USER
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      {/* Notification Modal */}
      {notifications.length > 0 && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4">
              <div className="bg-gray-800 rounded-xl max-w-md w-full p-6 shadow-2xl border border-red-600 animate-fade-in">
                  <h3 className="text-xl font-bold text-red-400 mb-4 text-center">{t('alert_missing_title')}</h3>
                  <div className="space-y-3 max-h-60 overflow-y-auto custom-scrollbar">
                      {notifications.map(notif => (
                          <div key={notif.id} className="bg-gray-700 p-3 rounded-lg flex items-center justify-between gap-3">
                              <div>
                                  <p className="font-bold text-white text-lg font-mono">{notif.partNumber}</p>
                                  <p className="text-sm text-gray-300">{notif.reason} - <span className="text-red-400">{notif.reportedBy}</span></p>
                                  <p className="text-xs text-gray-500">{new Date(notif.timestamp).toLocaleString('sk-SK')}</p>
                              </div>
                              <button onClick={() => props.onClearNotification(notif.id)} className="text-red-300 hover:text-red-500 p-2 rounded-full hover:bg-gray-600">
                                  <CheckCircleIcon className="w-6 h-6" />
                              </button>
                          </div>
                      ))}
                  </div>
                  <button onClick={() => notifications.forEach(n => props.onClearNotification(n.id))} className="mt-6 w-full py-3 bg-red-800/50 hover:bg-red-800 text-red-100 rounded-lg font-bold transition-colors">{t('alert_btn_ok')}</button>
              </div>
          </div>
      )}

      {/* Break Active Banner */}
      {props.isBreakActive && (
        <div className="bg-orange-800 text-white text-center py-2 px-4 shadow-md font-bold text-sm z-20">
          {t('break_active')} - {t('break_active_desc')}
        </div>
      )}

      {/* Success Message */}
      {showSuccessMessage && (
        <div className="fixed top-20 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">
          {t('sent_msg')}
        </div>
      )}

      {/* RE-DESIGNED HEADER */}
      <div className="bg-gray-900 shadow-2xl z-40 p-3 border-b border-gray-800 relative">
        <div className="max-w-7xl mx-auto w-full flex items-center justify-between relative">

          {/* LEFT: Language Toggle */}
          <div className="flex items-center z-10">
             <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700 shadow-inner">
                <button 
                    onClick={() => setLanguage('sk')} 
                    className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'sk' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                    SK
                </button>
                <button 
                    onClick={() => setLanguage('en')} 
                    className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'en' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                    EN
                </button>
             </div>
          </div>

          {/* RIGHT: User Info Pill & Buttons */}
          <div className="flex items-center gap-3 z-10">

             {/* User Role Pill */}
             <div className={`hidden md:flex items-center gap-2 px-4 py-1.5 rounded-full border ${getRoleBadgeColor(currentUserRole)} transition-all duration-300 shadow-lg`}>
                <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                <span className="text-xs font-bold uppercase tracking-wider text-white">{currentUser} | {currentUserRole}</span>
            </div>

             {/* Small Mobile User Name */}
             <span className="md:hidden text-xs font-bold text-gray-400">{currentUser}</span>

            {/* PWA Button */}
            {installPrompt && hasPermission('perm_install_pwa') && (
                <button 
                    onClick={onInstallApp}
                    className="bg-blue-600 hover:bg-blue-500 text-white p-2 rounded-lg transition-colors shadow-md border border-blue-500/50"
                    title={t('pwa_install_btn')}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M10 2a.75.75 0 01.75.75v6.5a.75.75 0 01-1.5 0V2.75A.75.75 0 0110 2z"/><path fillRule="evenodd" d="M3.5 9.25a.75.75 0 00-1.5 0v7a2 2 0 002 2h11a2 2 0 002-2v-7a.75.75 0 00-1.5 0v7a.5.5 0 01-.5.5h-11a.5.5 0 01-.5-.5v-7z" clipRule="evenodd"/></svg>
                </button>
            )}

            {/* Fullscreen Button */}
            {hasPermission('perm_view_fullscreen') && (
                <button 
                    onClick={handleToggleFullscreen} 
                    className="bg-gray-700 hover:bg-gray-600 text-teal-400 hover:text-white p-2 rounded-lg transition-all shadow-md border border-gray-600" 
                    title={isFullscreen ? t('fullscreen_off') : t('fullscreen_on')}
                >
                    {isFullscreen ? <ExitFullscreenIcon className="h-5 w-5" /> : <FullscreenIcon className="h-5 w-5" />}
                </button>
            )}

            {/* Logout Button */}
            <button 
                onClick={onLogout} 
                className="bg-red-600 hover:bg-red-500 text-white p-2 rounded-lg transition-all shadow-md border border-red-500/50" 
                title={t('logout')}
            >
              <LogoutIcon className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-10">
        <div className="max-w-7xl mx-auto w-full px-2 sm:px-4 overflow-x-auto custom-scrollbar">
          <div className="flex space-x-4 sm:space-x-6">
            {hasPermission('perm_tab_entry') && (
              <button onClick={() => setActiveTab('entry')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'entry' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>
                {t('tab_entry')}
              </button>
            )}
            {hasPermission('perm_tab_tasks') && (
              <button onClick={() => setActiveTab('tasks')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'tasks' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'} ${unfinishedTasksCount > 0 ? 'text-orange-400' : ''}`}>
                {t('tab_tasks')} {unfinishedTasksCount > 0 && <span className="ml-1 sm:ml-2 bg-orange-600 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5">{unfinishedTasksCount}</span>}
              </button>
            )}
            {hasPermission('perm_tab_bom') && (
              <button onClick={() => setActiveTab('bom')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'bom' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>
                {t('tab_bom')}
              </button>
            )}
            {hasPermission('perm_tab_missing') && (
              <button onClick={() => setActiveTab('missing')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'missing' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>
                {t('tab_missing')}
              </button>
            )}
            {hasPermission('perm_tab_analytics') && (
              <button onClick={() => setActiveTab('analytics')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'analytics' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>
                {t('tab_analytics')}
              </button>
            )}
            {hasPermission('perm_tab_settings') && (
              <button onClick={() => setActiveTab('settings')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'settings' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'} ${pendingRequestsCount > 0 ? 'text-red-400' : ''}`}>
                {t('tab_settings')} {pendingRequestsCount > 0 && <span className="ml-1 sm:ml-2 bg-red-500 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5">{pendingRequestsCount}</span>}
              </button>
            )}
            {hasPermission('perm_tab_permissions') && (
                <button onClick={() => setActiveTab('permissions')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'permissions' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>
                    {t('tab_permissions')}
                </button>
            )}
          </div>
        </div>
      </div>

      {/* Tab Content */}
      <div className="flex-grow overflow-y-auto p-2 md:p-6 custom-scrollbar">
        <div className="max-w-7xl mx-auto w-full h-full">

          {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
            <div className="h-full flex flex-col items-center animate-fade-in pb-20">
                <div className="w-full max-w-2xl">

                    {/* Main Form Card */}
                    <div className="bg-gray-800 p-4 sm:p-6 rounded-xl shadow-lg border border-gray-700 mb-6">

                        {/* MODE SWITCHER */}
                        {hasPermission('perm_logistics_mode') && (
                            <div className="flex bg-gray-900 p-1 rounded-lg mb-6 border border-gray-700">
                                <button 
                                    onClick={() => setEntryMode('production')}
                                    className={`flex-1 py-2 rounded-md text-sm font-bold transition-all ${entryMode === 'production' ? 'bg-teal-600 text-white shadow' : 'text-gray-400 hover:text-white'}`}
                                >
                                    🏭 {t('mode_production')}
                                </button>
                                <button 
                                    onClick={() => setEntryMode('logistics')}
                                    className={`flex-1 py-2 rounded-md text-sm font-bold transition-all ${entryMode === 'logistics' ? 'bg-orange-600 text-white shadow' : 'text-gray-400 hover:text-white'}`}
                                >
                                    🚚 {t('mode_logistics')}
                                </button>
                            </div>
                        )}

                        <h2 className="text-xl font-bold text-white mb-6 border-b border-gray-700 pb-2 text-center">
                            {entryMode === 'production' ? t('search_title') : t('mode_logistics')}
                        </h2>

                        <div className="space-y-4 sm:space-y-6">
                            {/* Priority */}
                            <div className="grid grid-cols-3 gap-2 sm:gap-3">
                                <button onClick={() => setPriority('LOW')} className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${priority === 'LOW' ? 'bg-slate-700 border-slate-500 text-white' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-slate-800'}`}>{t('prio_low')}</button>
                                <button onClick={() => setPriority('NORMAL')} className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${priority === 'NORMAL' ? 'bg-green-700 border-green-500 text-white' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-green-800'}`}>{t('prio_normal')}</button>
                                <button onClick={() => setPriority('URGENT')} className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${priority === 'URGENT' ? 'bg-red-700 border-red-500 text-white' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-red-800'}`}>{t('prio_urgent')}</button>
                            </div>

                            {/* FIELDS SWITCH based on Mode */}
                            {entryMode === 'production' ? (
                                <>
                                    {/* Part Number */}
                                    <div>
                                        <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('part_number')}:</label>
                                        <PartNumberInput 
                                            parts={parts.map(p => p.value)} 
                                            onPartSelect={(v) => setSelectedPart(parts.find(p => p.value === v) || null)} 
                                            value={selectedPart?.value || null} 
                                            placeholder={t('part_placeholder')} 
                                            onRequestPart={props.onRequestPart}
                                        />
                                        {selectedPart?.description && (
                                            <div className="mt-1 p-2 bg-gray-700/50 rounded border border-gray-600">
                                                <span className="text-xs text-gray-400 uppercase font-bold mr-2">{t('part_description')}:</span>
                                                <span className="text-teal-300 font-bold">{selectedPart.description}</span>
                                            </div>
                                        )}
                                    </div>

                                    {/* Workplace */}
                                    <div>
                                        <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('workplace')}:</label>
                                        <PartNumberInput 
                                            parts={workplaceStrings} 
                                            onPartSelect={setSelectedWorkplace} 
                                            value={selectedWorkplace} 
                                            placeholder={t('workplace_placeholder')} 
                                        />
                                    </div>
                                </>
                            ) : (
                                <>
                                    {/* Reference / Plate Number */}
                                    <div>
                                        <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('log_reference')}:</label>
                                        <input
                                            type="text"
                                            value={logisticsRef}
                                            onChange={(e) => setLogisticsRef(e.target.value.toUpperCase())}
                                            placeholder={t('log_reference_place')}
                                            className="w-full pl-4 pr-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-orange-500 transition-colors"
                                        />
                                    </div>

                                    {/* Operation Type Dropdown */}
                                    <div>
                                        <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('log_operation')}:</label>
                                        <select 
                                            value={logisticsOp}
                                            onChange={(e) => setLogisticsOp(e.target.value)}
                                            className="w-full bg-gray-700 border border-gray-600 rounded-lg text-white px-4 py-3 focus:outline-none focus:ring-2 focus:ring-orange-500 appearance-none"
                                        >
                                            <option value="" disabled>{t('workplace_placeholder')}</option>
                                            {logisticsOperationsList.map(op => (
                                                <option key={op.id} value={op.value}>{op.value}</option>
                                            ))}
                                        </select>
                                    </div>
                                </>
                            )}

                            {/* Quantity Section (Shared) */}
                            <div>
                                <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('quantity')}:</label>
                                <input 
                                    type="number" 
                                    value={quantity} 
                                    onChange={(e) => { if (e.target.value.length <= 6) setQuantity(e.target.value); }} 
                                    placeholder={t('pcs_placeholder')} 
                                    className={`w-full bg-gray-700 border border-gray-600 rounded-lg text-white px-4 py-3 focus:outline-none focus:ring-2 mb-2 ${entryMode === 'logistics' ? 'focus:ring-orange-500' : 'focus:ring-teal-500'}`}
                                />
                                <div className="grid grid-cols-3 gap-2 sm:gap-3">
                                    <button 
                                        onClick={() => setQuantityUnit('pcs')} 
                                        disabled={entryMode === 'logistics'}
                                        className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${
                                            entryMode === 'logistics' 
                                            ? 'bg-gray-800 border-gray-700 text-gray-600 cursor-not-allowed opacity-50'
                                            : quantityUnit === 'pcs' ? 'bg-teal-700 border-teal-500 text-white' : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'
                                        }`}
                                    >
                                        {t('unit_pcs')}
                                    </button>
                                    <button 
                                        onClick={() => setQuantityUnit('boxes')} 
                                        className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${quantityUnit === 'boxes' ? (entryMode === 'logistics' ? 'bg-orange-700 border-orange-500 text-white' : 'bg-teal-700 border-teal-500 text-white') : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                                    >
                                        {t('unit_boxes')}
                                    </button>
                                    <button 
                                        onClick={() => setQuantityUnit('pallet')} 
                                        className={`py-3 px-2 rounded-lg font-bold text-xs sm:text-sm transition-colors border ${quantityUnit === 'pallet' ? (entryMode === 'logistics' ? 'bg-orange-700 border-orange-500 text-white' : 'bg-teal-700 border-teal-500 text-white') : 'bg-gray-700 border-gray-600 text-gray-400 hover:bg-gray-600'}`}
                                    >
                                        {t('unit_pallet')}
                                    </button>
                                </div>
                            </div>

                            {/* Submit Button */}
                            <button 
                                onClick={handleSendToTasks} 
                                disabled={
                                    entryMode === 'production' 
                                    ? (!selectedPart || !selectedWorkplace || !quantity || props.isBreakActive)
                                    : (!logisticsRef || !logisticsOp || !quantity || props.isBreakActive)
                                }
                                className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg transition-all duration-200 transform active:scale-95 ${
                                    (entryMode === 'production' ? (!selectedPart || !selectedWorkplace || !quantity || props.isBreakActive) : (!logisticsRef || !logisticsOp || !quantity || props.isBreakActive))
                                    ? 'bg-gray-700 text-gray-500 cursor-not-allowed border border-gray-600' 
                                    : (priority === 'URGENT' 
                                        ? 'bg-red-600 hover:bg-red-700 text-white border border-red-500' 
                                        : (entryMode === 'logistics' ? 'bg-orange-600 hover:bg-orange-700 text-white border border-orange-500' : 'bg-teal-600 hover:bg-teal-700 text-white border border-teal-500')
                                      )
                                }`}
                            >
                                {priority === 'URGENT' ? t('send_urgent_btn') : t('send_btn')}
                                {props.isBreakActive && <span className="block text-xs mt-1 opacity-75">{t('break_blocked_msg')}</span>}
                            </button>
                        </div>
                    </div>

                    {/* Quick Tips Section - Below the window */}
                    <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700 opacity-75">
                        <h3 className="text-lg font-bold text-gray-300 mb-4">💡 Rýchle tipy</h3>
                        <ul className="list-disc list-inside text-gray-400 space-y-2 text-sm">
                            <li>Prepnite na <strong>LOGISTIKU</strong> pre evidenciu vykládok a nakládok.</li>
                            <li>Použite <strong>*</strong> pre vyhľadávanie časti čísla (napr. 332*).</li>
                            <li>Pre urgentné úlohy zvoľte prioritu <strong>URGENT</strong>.</li>
                            <li>Ak diel nenájdete, môžete ho nahlásiť adminovi priamo z vyhľadávania.</li>
                        </ul>
                    </div>
                </div>
            </div>
          )}

          {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
            <div className="space-y-4 animate-fade-in">
              <div className="flex flex-col sm:flex-row justify-between items-center gap-4 mb-2">
                  <h2 className="text-2xl font-bold text-teal-400">{t('tasks_title')}</h2>
                  <div className="flex-1 w-full sm:max-w-md">
                        <input 
                            type="text" 
                            value={taskSearchQuery} 
                            onChange={(e) => setTaskSearchQuery(e.target.value)} 
                            placeholder={t('task_search_placeholder')}
                            className="w-full bg-gray-800 border border-gray-600 rounded-lg text-white placeholder-gray-500 px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500"
                        />
                  </div>
                   <button 
                        onClick={handleExportTasks}
                        className="bg-green-700 hover:bg-green-600 text-white px-3 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-sm"
                    >
                        <DownloadIcon className="w-4 h-4" />
                        {t('export_excel')}
                    </button>
              </div>

              <TaskList 
                currentUser={currentUserRole} 
                currentUserName={currentUser}
                tasks={tasks.filter(task => 
                  task.text.toLowerCase().includes(taskSearchQuery.toLowerCase()) ||
                  (task.partNumber && task.partNumber.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.workplace && task.workplace.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.createdBy && task.createdBy.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.inProgressBy && task.inProgressBy.toLowerCase().includes(taskSearchQuery.toLowerCase())) ||
                  (task.missingReason && task.missingReason.toLowerCase().includes(taskSearchQuery.toLowerCase()))
                )} 
                missingReasons={props.missingReasons}
                onToggleTask={props.onToggleTask} 
                onEditTask={props.onEditTask} 
                onDeleteTask={props.onDeleteTask} 
                onToggleMissing={props.onToggleMissing}
                onSetInProgress={props.onSetInProgress}
                onToggleBlock={props.onToggleBlock}
                onMarkAsIncorrect={props.onMarkAsIncorrect}
                onAddNote={props.onAddNote}
                onReleaseTask={props.onReleaseTask}
                hasPermission={hasPermission}
              />
            </div>
          )}

          {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
            <div className="animate-fade-in space-y-6">
                <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700">
                    <h2 className="text-xl font-bold text-white mb-4 border-b border-gray-700 pb-2">{t('bom_title')}</h2>
                    <div className="grid grid-cols-1 lg:grid-cols-4 gap-4 items-end">
                        <div className="lg:col-span-1">
                            <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('bom_parent')}:</label>
                            <PartNumberInput 
                                parts={props.parts.map(p => p.value)} 
                                onPartSelect={(v) => setBomParentQuery(v || '')} 
                                value={bomParentQuery} 
                                placeholder={t('bom_parent_place')} 
                                onRequestPart={props.onRequestBOM} 
                            />
                        </div>
                        <div className="lg:col-span-1">
                            <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('bom_qty')}:</label>
                            <input 
                                type="number" 
                                value={bomQuantity} 
                                onChange={(e) => setBomQuantity(e.target.value)} 
                                placeholder={t('bom_qty_place')} 
                                className="w-full bg-gray-700 border border-gray-600 rounded-lg text-white px-4 py-3 focus:outline-none focus:ring-2 focus:ring-teal-500"
                            />
                        </div>
                        <div className="lg:col-span-1">
                            <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('bom_select_wp')}:</label>
                            <PartNumberInput 
                                parts={workplaceStrings} 
                                onPartSelect={setBomSelectedWorkplace} 
                                value={bomSelectedWorkplace} 
                                placeholder={t('workplace_placeholder')} 
                            />
                        </div>
                        <div className="lg:col-span-1">
                            <button 
                                onClick={handleCalculateBOM}
                                className="w-full py-3 px-6 rounded-lg font-bold text-white bg-teal-600 hover:bg-teal-700 transition-colors shadow-md border border-teal-500 h-[50px]"
                                disabled={!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0}
                            >
                                {t('bom_calc_btn')}
                            </button>
                        </div>
                    </div>
                </div>

                {displayedBomParent && (
                    <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700">
                        <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                            {t('bom_results')} 
                            <span className="text-sm font-normal text-gray-400">({displayedBomParent} × {displayedBomQuantity})</span>
                        </h3>

                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {filteredBomItems.length > 0 ? (
                                filteredBomItems.map(item => {
                                    const requiredQty = item.quantity * (displayedBomQuantity || 0); 
                                    const isTaskCreated = clickedBOMTasks.has(item.id);
                                    return (
                                        <div key={item.id} className="bg-gray-700 p-4 rounded-lg border border-gray-600 flex flex-col justify-between h-full">
                                            <div className="mb-4">
                                                <p className="text-xs text-gray-400 uppercase font-bold">{t('bom_child')}</p>
                                                <p className="font-bold text-white text-lg font-mono tracking-wide">{item.childPart}</p>
                                                <div className="mt-2 flex justify-between items-end border-t border-gray-600 pt-2">
                                                    <span className="text-gray-400 text-sm">Norma: {item.quantity}</span>
                                                    <span className="text-green-400 font-bold text-xl">{requiredQty.toFixed(2)}</span>
                                                </div>
                                            </div>

                                            {bomSelectedWorkplace && !isTaskCreated && (
                                                <button 
                                                    onClick={() => handleCreateTaskFromBOM(item.childPart, requiredQty, item.id)} 
                                                    className="w-full bg-blue-600 hover:bg-blue-700 text-white py-2 rounded font-bold text-sm transition-colors"
                                                >
                                                    {t('bom_create_task')}
                                                </button>
                                            )}
                                            {isTaskCreated && (
                                                <div className="w-full bg-green-900/50 text-green-400 py-2 rounded font-bold text-sm text-center border border-green-800">
                                                    ✓ {t('task_created')}
                                                </div>
                                            )}
                                        </div>
                                    );
                                })
                            ) : (
                                <div className="col-span-full py-8 flex flex-col items-center justify-center border-2 border-dashed border-gray-700 rounded-xl space-y-4">
                                    <p className="text-gray-500 italic">{t('bom_no_results')}</p>
                                    <button 
                                        onClick={handleRequestBOM}
                                        disabled={bomRequestStatus !== 'idle'}
                                        className={`px-6 py-3 font-bold rounded-lg shadow-md flex items-center justify-center gap-2 transition-all duration-200 hover:scale-[1.01] border ${
                                            bomRequestStatus === 'success' 
                                            ? 'bg-green-600 border-green-500 text-white cursor-default' 
                                            : bomRequestStatus === 'loading'
                                            ? 'bg-yellow-800 border-yellow-700 text-yellow-200 cursor-wait'
                                            : 'bg-yellow-700 hover:bg-yellow-600 border-yellow-500 text-white'
                                        }`}
                                    >
                                        {bomRequestStatus === 'loading' ? (
                                                <span>{t('report_btn_loading')}</span>
                                        ) : bomRequestStatus === 'success' ? (
                                                <span>{t('report_btn_success')}</span>
                                        ) : (
                                            <>
                                                <PlusIcon className="w-5 h-5 text-yellow-200" />
                                                <span>{t('bom_request_btn')}</span>
                                            </>
                                        )}
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>
          )}

          {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
            <AnalyticsTab 
                tasks={tasks} 
                onFetchArchivedTasks={props.onFetchArchivedTasks}
                systemBreaks={props.systemBreaks} 
            />
          )}

          {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
              <MissingItemsTab 
                  tasks={tasks} 
                  onDeleteMissingItem={props.onDeleteMissingItem}
                  hasPermission={hasPermission}
              />
          )}

          {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
            <SettingsTab 
              currentUserRole={currentUserRole}
              users={props.users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser}
              parts={props.parts} workplaces={props.workplaces} missingReasons={props.missingReasons} logisticsOperations={props.logisticsOperations}
              onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts}
              onAddWorkplace={props.onAddWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces}
              onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason}
              onAddLogisticsOperation={props.onAddLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation}
              partRequests={props.partRequests} onApprovePartRequest={props.onApprovePartRequest} onRejectPartRequest={props.onRejectPartRequest}
              onArchiveTasks={props.onArchiveTasks}
              breakSchedules={props.breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule}
              bomItems={props.bomItems} bomRequests={props.bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={props.onApproveBOMRequest} onRejectBOMRequest={props.onRejectBOMRequest}
              roles={props.roles} permissions={props.permissions} onAddRole={props.onAddRole} onDeleteRole={props.onDeleteRole} onUpdatePermission={props.onUpdatePermission}
              installPrompt={installPrompt} onInstallApp={onInstallApp}
            />
          )}

          {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                <PermissionsTab 
                    roles={props.roles} 
                    permissions={props.permissions} 
                    onAddRole={props.onAddRole} 
                    onDeleteRole={props.onDeleteRole} 
                    onUpdatePermission={props.onUpdatePermission}
                    onVerifyAdminPassword={props.onVerifyAdminPassword}
                />
            )}
        </div>
      </div>
    </div>
  );
};

export default PartSearchScreen;

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { Role, Permission } from '../App'; 
import { useLanguage } from './LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    permissions: Permission[];
    onAddRole: (name: string) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const LockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
);

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, permissions, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');

    // Modal State
    const [deleteModalRole, setDeleteModalRole] = useState<Role | null>(null);
    const [passwordInput, setPasswordInput] = useState('');
    const [error, setError] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_missing', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_permissions', 'perm_logistics_mode'] 
      },
      {
          name: 'perm_group_actions',
          perms: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_return', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_lock', 'perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const handleAddRole = (e: React.FormEvent) => {
      e.preventDefault();
      if (newRoleName.trim()) {
          onAddRole(newRoleName.trim());
          setNewRoleName('');
      }
    };

    const hasPermission = (roleId: string, permName: string) => {
        return permissions?.some(p => p.roleId === roleId && p.permissionName === permName) || false;
    };

    // Sort roles: System roles first, then custom roles alphabetically
    const sortedRoles = [...roles].sort((a, b) => {
        if (a.isSystem && !b.isSystem) return -1;
        if (!a.isSystem && b.isSystem) return 1;
        return a.name.localeCompare(b.name);
    });

    const handleDeleteClick = (e: React.MouseEvent, role: Role) => {
        e.preventDefault();
        e.stopPropagation();
        setDeleteModalRole(role);
        setPasswordInput('');
        setError('');
    };

    const handleConfirmDelete = () => {
        if (deleteModalRole) {
            if (onVerifyAdminPassword(passwordInput)) {
                onDeleteRole(deleteModalRole.id);
                setDeleteModalRole(null);
                setPasswordInput('');
                setError('');
            } else {
                setError(t('err_pass_incorrect'));
            }
        }
    };

    const handleCloseModal = () => {
        setDeleteModalRole(null);
        setPasswordInput('');
        setError('');
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 pb-8 animate-fade-in relative">
            <h1 className="text-center text-2xl sm:text-3xl font-bold text-orange-400 mb-6 sm:mb-8">{t('sect_roles')}</h1>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-xl p-6 shadow-lg border border-gray-700">
                     <h3 className="text-lg font-bold text-gray-300 mb-4 border-b border-gray-700 pb-2">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[600px] w-full text-left text-sm border-collapse">
                             <thead>
                                 <tr className="border-b-2 border-gray-700">
                                     <th className="py-3 px-4 text-gray-400 font-semibold w-1/3 min-w-[200px]">{t('permission_label')}</th> 
                                     {sortedRoles.map(role => (
                                         <th key={role.id} className="py-3 px-4 text-white font-bold text-center">
                                             <div className="flex items-center justify-center gap-1">
                                                 {role.name}
                                                 {role.name !== 'ADMIN' && (
                                                     <button 
                                                         type="button"
                                                         onClick={(e) => handleDeleteClick(e, role)} 
                                                         className="ml-2 text-red-600 hover:text-red-400 transition-colors p-1 focus:outline-none"
                                                         title={t('perm_btn_delete')}
                                                     >
                                                         <TrashIcon className="w-4 h-4" />
                                                     </button>
                                                 )}
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody>
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="border-b border-gray-800 hover:bg-gray-800/50">
                                         <td className="py-3 px-4 text-gray-300">{t(perm as any)}</td>
                                         {sortedRoles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-3 px-4 text-center">
                                                 <input 
                                                     type="checkbox" 
                                                     checked={hasPermission(role.id, perm)} 
                                                     onChange={(e) => onUpdatePermission(perm, role.name, e.target.checked)}
                                                     className="w-5 h-5 text-orange-500 bg-gray-700 border-gray-600 rounded focus:ring-orange-500 focus:ring-2" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}

            <div className="bg-gray-900 rounded-xl p-6 shadow-lg border border-gray-700">
                 <h3 className="text-lg font-bold text-gray-300 mb-4">{t('role_add_new_title')}</h3> 
                 <form onSubmit={handleAddRole} className="flex flex-col sm:flex-row gap-2 max-w-sm mt-4">
                     <input value={newRoleName} onChange={e => setNewRoleName(e.target.value)} placeholder={t('role_name_place')} className="flex-1 bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white text-sm uppercase" />
                     <button type="submit" className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded font-semibold">{t('role_add_btn')}</button>
                 </form>
             </div>

             {/* Delete Confirmation Modal */}
             {deleteModalRole && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={handleCloseModal}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-6">
                            <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/50">
                                <LockIcon className="w-8 h-8 text-red-500" />
                            </div>
                            <h3 className="text-xl font-bold text-white mb-2">{t('role_delete_modal_title')}</h3>
                            <p className="text-gray-400 text-sm">
                                {t('role_delete_confirm')}
                                <br/>
                                <span className="font-bold text-red-400">{deleteModalRole.name}</span>
                            </p>
                        </div>

                        <div className="mb-6">
                            <label className="block text-gray-400 text-xs font-bold uppercase mb-2">{t('role_delete_pass_label')}</label>
                            <input 
                                type="password" 
                                value={passwordInput} 
                                onChange={(e) => {
                                    setPasswordInput(e.target.value);
                                    setError('');
                                }}
                                className="w-full bg-gray-700 border border-gray-600 rounded-lg text-white px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500"
                                placeholder="********"
                                autoFocus
                            />
                            {error && <p className="text-red-500 text-sm mt-2 font-bold animate-pulse">{error}</p>}
                        </div>

                        <div className="flex gap-3">
                             <button 
                                onClick={handleCloseModal} 
                                className="flex-1 py-3 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={handleConfirmDelete} 
                                disabled={!passwordInput}
                                className={`flex-1 py-3 text-white rounded-lg font-bold transition-colors shadow-lg flex items-center justify-center gap-2 ${!passwordInput ? 'bg-red-900/50 cursor-not-allowed text-gray-400' : 'bg-red-600 hover:bg-red-700'}`}
                            >
                                <TrashIcon className="w-5 h-5" />
                                {t('role_delete_btn')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default PermissionsTab;

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { UserData, DBItem, PartRequest, BreakSchedule, BOMItem, BOMRequest, Role, Permission } from '../App';
import { useLanguage } from './LanguageContext';

interface SettingsTabProps {
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateUserRole: (username: string, newRole: 'ADMIN' | 'USER' | 'LEADER') => void;
  onDeleteUser: (username: string) => void;
  // DB Props
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (id: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  // Logistics Ops
  logisticsOperations?: DBItem[];
  onAddLogisticsOperation?: (val: string) => void;
  onDeleteLogisticsOperation?: (id: string) => void;
  // Requests
  partRequests: PartRequest[];
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  // Archive
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  // Breaks
  breakSchedules: BreakSchedule[];
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  // BOM
  bomItems: BOMItem[]; 
  bomRequests: BOMRequest[]; 
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (id: string) => void;
  onDeleteAllBOMItems: () => void;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  // Roles
  roles: Role[];
  permissions: Permission[]; 
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  // PWA
  installPrompt: any;
  onInstallApp: () => void;
}

const EyeIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
    </svg>
);

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const ExclamationIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
    </svg>
);

const SettingsTab: React.FC<SettingsTabProps> = ({ 
  currentUserRole,
  users, onAddUser, onUpdatePassword, onUpdateUserRole, onDeleteUser,
  parts, workplaces, missingReasons, onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
  onAddWorkplace, onBatchAddWorkplaces, onDeleteWorkplace, onDeleteAllWorkplaces,
  onAddMissingReason, onDeleteMissingReason,
  logisticsOperations = [], onAddLogisticsOperation, onDeleteLogisticsOperation,
  partRequests, onApprovePartRequest, onRejectPartRequest, onArchiveTasks,
  breakSchedules, onAddBreakSchedule, onDeleteBreakSchedule,
  bomItems, bomRequests, onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems, onApproveBOMRequest, onRejectBOMRequest,
  roles, permissions, onAddRole, onDeleteRole, onUpdatePermission,
  installPrompt, onInstallApp
}) => {
  // User State
  const [newUser, setNewUser] = useState('');
  const [newPass, setNewPass] = useState('');
  const [newRole, setNewRole] = useState<'USER' | 'ADMIN' | 'LEADER'>('USER');
  const [userError, setUserError] = useState('');
  const [passwordInputs, setPasswordInputs] = useState<Record<string, string>>({});
  const [visiblePasswords, setVisiblePasswords] = useState<Record<string, boolean>>({});

  // DB State
  const [newPart, setNewPart] = useState('');
  const [newPartDesc, setNewPartDesc] = useState('');
  const [bulkParts, setBulkParts] = useState('');
  const [partSearch, setPartSearch] = useState('');

  const [newWorkplace, setNewWorkplace] = useState('');
  const [newWorkplaceTime, setNewWorkplaceTime] = useState('');
  const [bulkWorkplaces, setBulkWorkplaces] = useState('');
  const [wpSearch, setWpSearch] = useState('');

  const [newMissingReason, setNewMissingReason] = useState('');
  const [reasonSearch, setReasonSearch] = useState('');

  const [newLogOp, setNewLogOp] = useState('');
  const [logOpSearch, setLogOpSearch] = useState('');

  const [successMsg, setSuccessMsg] = useState('');
  const [isArchiving, setIsArchiving] = useState(false);

  // Break State
  const [newBreakStart, setNewBreakStart] = useState('');
  const [newBreakEnd, setNewBreakEnd] = useState('');

  // BOM State
  const [bomParent, setBomParent] = useState('');
  const [bomChild, setBomChild] = useState('');
  const [bomQty, setBomQty] = useState('');
  const [bomBulk, setBomBulk] = useState('');
  const [bomSearchQuery, setBomSearchQuery] = useState('');

  // Confirmation Modal State
  const [confirmModal, setConfirmModal] = useState<{
      isOpen: boolean;
      title: string;
      message: string | React.ReactNode;
      onConfirm: () => void;
  }>({
      isOpen: false,
      title: '',
      message: '',
      onConfirm: () => {}
  });

  const { t } = useLanguage();

  const isAdmin = currentUserRole === 'ADMIN';
  const canManageDB = isAdmin; // Simplified since Logistician removed

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = (permName: string) => {
      // Safety: Admin always has access 
      if (currentUserRole === 'ADMIN') return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  };

  const canManageLogOps = hasPermission('perm_manage_logistics_ops');

  const showSuccess = (msg: string) => {
    setSuccessMsg(msg);
    setTimeout(() => setSuccessMsg(''), 3000);
  };

  // Helper to open confirm modal
  const openConfirmModal = (title: string, message: string, action: () => void) => {
      setConfirmModal({
          isOpen: true,
          title,
          message,
          onConfirm: action
      });
  };

  const closeConfirmModal = () => {
      setConfirmModal(prev => ({ ...prev, isOpen: false }));
  };

  const handleConfirmAction = () => {
      confirmModal.onConfirm();
      closeConfirmModal();
  };

  // --- Filter Helpers ---
  const filteredParts = parts.filter(p => 
      p.value.toLowerCase().includes(partSearch.toLowerCase()) || 
      (p.description && p.description.toLowerCase().includes(partSearch.toLowerCase()))
  );
  const filteredWorkplaces = workplaces.filter(w => w.value.toLowerCase().includes(wpSearch.toLowerCase()));
  const filteredReasons = missingReasons.filter(r => r.value.toLowerCase().includes(reasonSearch.toLowerCase()));
  const filteredLogOps = logisticsOperations.filter(op => op.value.toLowerCase().includes(logOpSearch.toLowerCase()));

  // --- User Handlers ---
  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUser.trim() || !newPass.trim()) { setUserError(t('user_fill')); return; }
    if (users.some(u => u.username.toUpperCase() === newUser.toUpperCase())) { setUserError(t('user_exists')); return; }
    onAddUser({ username: newUser, password: newPass, role: newRole });
    setNewUser(''); setNewPass(''); setUserError('');
    showSuccess(t('user_added_success', { username: newUser })); // Added translation
  };

  const handleSavePassword = (username: string) => {
    const pass = passwordInputs[username];
    if (!pass?.trim()) return;
    onUpdatePassword(username, pass);
    setPasswordInputs(prev => ({ ...prev, [username]: '' }));
    showSuccess(t('password_changed_success', { username })); // Added translation
  };

  const togglePasswordVisibility = (username: string) => {
      setVisiblePasswords(prev => ({ ...prev, [username]: !prev[username] }));
  };

  const handleDeleteUserClick = (username: string) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_user', { name: username }),
          () => onDeleteUser(username)
      );
  };

  // --- DB Handlers ---
  const handleAddSinglePart = (e: React.FormEvent) => {
    e.preventDefault();
    if(newPart.trim()) {
      onAddPart(newPart.trim(), newPartDesc.trim());
      setNewPart('');
      setNewPartDesc('');
      showSuccess(t('part_added_success')); // Added translation
    }
  };

  const handleBulkAddParts = () => {
    const lines = bulkParts.split('\n').map(l => l.trim()).filter(l => l !== '');
    if (lines.length > 0) {
      onBatchAddParts(lines);
      setBulkParts('');
      showSuccess(t('parts_bulk_added_success', { count: lines.length })); // Added translation
    }
  };

  const handleDeletePartClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_part', { name: item.value }),
          () => onDeletePart(item.id)
      );
  };

  const handleDeleteAllPartsConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_parts_confirm'),
          () => {
              onDeleteAllParts();
              showSuccess(t('all_parts_deleted_success'));
          }
      );
  };

  const handleAddSingleWP = (e: React.FormEvent) => {
    e.preventDefault();
    if(newWorkplace.trim()) {
      const time = parseInt(newWorkplaceTime, 10);
      onAddWorkplace(newWorkplace.trim(), isNaN(time) ? 0 : time);
      setNewWorkplace('');
      setNewWorkplaceTime('');
      showSuccess(t('wp_added_success')); // Added translation
    }
  };

  const handleBulkAddWP = () => {
    const lines = bulkWorkplaces.split('\n').map(l => l.trim()).filter(l => l !== '');
    if (lines.length > 0) {
      onBatchAddWorkplaces(lines);
      setBulkWorkplaces('');
      showSuccess(t('wp_bulk_added_success', { count: lines.length })); // Added translation
    }
  };

  const handleDeleteWorkplaceClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_wp', { name: item.value }),
          () => onDeleteWorkplace(item.id)
      );
  };

  const handleDeleteAllWPConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_workplaces_confirm'),
          () => {
              onDeleteAllWorkplaces();
              showSuccess(t('all_workplaces_deleted_success'));
          }
      );
  };

  const handleAddReason = (e: React.FormEvent) => {
      e.preventDefault();
      if(newMissingReason.trim()) {
          onAddMissingReason(newMissingReason.trim());
          setNewMissingReason('');
          showSuccess(t('reason_added_success')); // Added translation
      }
  };

  const handleDeleteReasonClick = (item: DBItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_reason', { name: item.value }),
          () => onDeleteMissingReason(item.id)
      );
  };

  const handleAddLogOp = (e: React.FormEvent) => {
      e.preventDefault();
      if(newLogOp.trim() && onAddLogisticsOperation) {
          onAddLogisticsOperation(newLogOp.trim());
          setNewLogOp('');
          showSuccess(t('op_added_success'));
      }
  };

  const handleDeleteLogOpClick = (item: DBItem) => {
      if(onDeleteLogisticsOperation) {
          openConfirmModal(
              t('modal_confirm_title'),
              t('msg_delete_log_op', { name: item.value }),
              () => onDeleteLogisticsOperation(item.id)
          );
      }
  };

  const handleRunArchiving = async () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('archive_confirm'),
          async () => {
              setIsArchiving(true);
              const result = await onArchiveTasks();
              setIsArchiving(false);

              if (result.success) {
                  if (result.count === 0 && result.message) {
                       alert(result.message);
                  } else {
                       alert(t('archive_success', { count: result.count || 0 }));
                  }
              } else {
                  alert(t('archive_error', { error: result.error || 'Unknown' }));
              }
          }
      );
  };

  const handleAddBreak = (e: React.FormEvent) => {
      e.preventDefault();
      if (newBreakStart && newBreakEnd) {
          onAddBreakSchedule(newBreakStart, newBreakEnd);
          setNewBreakStart('');
          setNewBreakEnd('');
          showSuccess(t('break_added_success')); // Added translation
      }
  };

  const handleDeleteBreakClick = (id: string) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_break'),
          () => onDeleteBreakSchedule(id)
      );
  };

  const handleAddBOM = (e: React.FormEvent) => {
      e.preventDefault();
      if(bomParent && bomChild && bomQty) {
          onAddBOMItem(bomParent, bomChild, parseFloat(bomQty));
          setBomParent(''); setBomChild(''); setBomQty('');
          showSuccess(t('bom_added_success')); // Added translation
      }
  };

  const handleBulkAddBOM = () => {
      const lines = bomBulk.split('\n').map(l => l.trim()).filter(l => l !== '');
      if (lines.length > 0) {
          onBatchAddBOMItems(lines);
          setBomBulk('');
          showSuccess(t('bom_bulk_added_success', { count: lines.length })); // Added translation
      }
  }

  const handleDeleteBOMClick = (item: BOMItem) => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('msg_delete_bom', { parent: item.parentPart, child: item.childPart }),
          () => onDeleteBOMItem(item.id)
      );
  };

  const handleDeleteAllBOMConfirm = () => {
      openConfirmModal(
          t('modal_confirm_title'),
          t('delete_all_bom_confirm'),
          () => {
              onDeleteAllBOMItems();
              showSuccess(t('all_bom_deleted_success'));
          }
      );
  }

  const filteredBOMItems = bomItems.filter(item => 
      item.parentPart.toLowerCase().includes(bomSearchQuery.toLowerCase()) || 
      item.childPart.toLowerCase().includes(bomSearchQuery.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-8 animate-fade-in relative">
      {successMsg && <div className="fixed top-4 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">{successMsg}</div>}

      {/* REQUESTS */}
      <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-yellow-700/50">
          <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
              <h2 className="text-xl font-bold text-yellow-400">{t('req_title')}</h2>
              {(partRequests.length > 0 || bomRequests.length > 0) && <span className="bg-yellow-500 text-black text-xs font-bold px-2 py-1 rounded-full animate-pulse">{partRequests.length + bomRequests.length} {t('req_waiting')}</span>}
          </div>
          {partRequests.length > 0 || bomRequests.length > 0 ? ( 
              <div className="space-y-3">
                  {/* Part Requests */}
                  {partRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_part')}:</span>
                                {req.partNumber}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApprovePartRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectPartRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
                  {/* BOM Requests */}
                  {bomRequests.map(req => (
                      <div key={req.id} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg border border-gray-700">
                          <div>
                            <p className="font-bold text-white text-lg font-mono">
                                <span className="text-gray-400 font-normal text-base mr-2">{t('req_type_bom')}:</span>
                                {req.parentPart}
                            </p>
                            <p className="text-sm text-gray-400">{t('requested_by')}: {req.requestedBy} ({new Date(req.requestedAt).toLocaleString('sk-SK')})</p>
                          </div>
                          <div className="flex gap-2 mt-3 sm:mt-0">
                               <button onClick={() => onApproveBOMRequest(req)} className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded text-sm font-bold">✓ {t('req_approve')}</button>
                               <button onClick={() => onRejectBOMRequest(req.id)} className="bg-red-900 hover:bg-red-700 text-red-200 px-4 py-2 rounded text-sm font-bold">✕ {t('req_reject')}</button>
                          </div>
                      </div>
                  ))}
              </div>
          ) : <p className="text-gray-500 italic text-center py-4">{t('no_requests')}</p>}
      </div>

      {/* 1. USERS */}
      <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-gray-700">
        <h2 className="text-xl font-bold text-teal-400 mb-6 border-b border-gray-700 pb-2">{t('sect_users_manage')}</h2>
        <div className="space-y-4 mb-8">
          {users.map((user) => (
              <div key={user.username} className="flex flex-col sm:flex-row sm:items-center justify-between bg-gray-800 p-4 rounded-lg gap-4">
                <div className="flex items-center gap-3 min-w-[150px]">
                  <div className={`w-3 h-3 rounded-full ${user.role === 'ADMIN' ? 'bg-red-500' : 'bg-teal-500'}`}></div>
                  <div>
                    <div className="flex items-center gap-2">
                        <p className="font-bold text-white">{user.username}</p>
                        {isAdmin && (
                            <button onClick={() => togglePasswordVisibility(user.username)} className="text-gray-500 hover:text-white" title={t('user_show_pass')}><EyeIcon className="w-4 h-4" /></button>
                        )}
                    </div>
                    {visiblePasswords[user.username] && isAdmin && <p className="text-xs text-yellow-400 font-mono mt-1">{user.password}</p>}
                    {isAdmin && user.username !== 'ADMIN' ? ( 
                       <select value={user.role} onChange={(e) => onUpdateUserRole(user.username, e.target.value as any)} className="mt-1 text-xs bg-gray-700 text-white border border-gray-600 rounded">
                           {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
                       </select>
                    ) : <p className="text-xs text-gray-500">{user.role}</p>}
                  </div>
                </div>
                {(isAdmin) && (
                  <div className="flex flex-1 gap-2 items-center">
                    <input type="text" placeholder={t('new_password_placeholder')} value={passwordInputs[user.username] || ''} onChange={(e) => setPasswordInputs(p => ({ ...p, [user.username]: e.target.value }))} className="flex-1 min-w-0 bg-gray-700 border border-gray-600 rounded px-3 py-2 text-sm text-white" />
                    <button onClick={() => handleSavePassword(user.username)} className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded text-sm font-semibold whitespace-nowrap">{t('btn_save')}</button>
                    {(isAdmin && user.username !== 'ADMIN') && <button onClick={() => handleDeleteUserClick(user.username)} className="bg-red-900 hover:bg-red-700 text-red-100 px-3 py-2 rounded text-sm">X</button>}
                  </div>
                )}
              </div>
          ))}
        </div>
        <form onSubmit={handleAddUser} className="bg-gray-800 p-4 rounded-lg">
          <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 items-end">
            <div><input value={newUser} onChange={e => setNewUser(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white" placeholder={t('user_name')} /></div>
            <div><input value={newPass} onChange={e => setNewPass(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white" placeholder={t('user_pass')} /></div>
            <div>
              <select value={newRole} onChange={e => setNewRole(e.target.value as any)} className="w-full bg-gray-700 border border-gray-600 rounded px-3 py-2 text-white">
                {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
              </select>
            </div>
            <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded font-semibold">{t('user_add_btn')}</button>
          </div>
          {userError && <p className="text-red-400 text-sm mt-2">{userError}</p>}
        </form>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* 2. PARTS */}
        <div className="bg-gray-900 rounded-xl p-4 sm:p-6 shadow-lg border border-gray-700 flex flex-col h-full">
          <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
              <h2 className="text-xl font-bold text-teal-400">{t('sect_parts')}</h2>
              {canManageDB && parts.length > 0 && <button onClick={handleDeleteAllPartsConfirm} className="text-xs bg-red-900 hover:bg-red-800 text-red-100 px-3 py-1 rounded">{t('delete_all')}</button>}
          </div>
