                                filteredBomItems.map(item => {
                                    const requiredQty = item.quantity * (displayedBomQuantity || 0); 
                                    const isTaskCreated = clickedBOMTasks.has(item.id);
                                    return (
                                        <div key={item.id} className="bg-gray-700 p-4 rounded-lg border border-gray-600 flex flex-col justify-between h-full">
                                            <div className="mb-4">
                                                <p className="text-xs text-gray-400 uppercase font-bold">{t('bom_child')}</p>
                                                <p className="font-bold text-white text-lg font-mono tracking-wide">{item.childPart}</p>
                                                <div className="mt-2 flex justify-between items-end border-t border-gray-600 pt-2">
                                                    <span className="text-gray-400 text-sm">Norma: {item.quantity}</span>
                                                    <span className="text-green-400 font-bold text-xl">{requiredQty.toFixed(2)}</span>
                                                </div>
                                            </div>

                                            {bomSelectedWorkplace && !isTaskCreated && (
                                                <button 
                                                    onClick={() => handleCreateTaskFromBOM(item.childPart, requiredQty, item.id)} 
