                                    type="text" 
                                    value={bomParentQuery} 
                                    onChange={(e) => setBomParentQuery(e.target.value)} 
                                    className="w-full pl-10 pr-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500"
