                          {t('bom_calc_btn')}
                      </button>

                      {/* WORKPLACE SELECTOR FOR TASK CREATION */}
                      {filteredBomItems.length > 0 && (
                          <div className="mb-6 p-4 bg-gray-900 rounded-lg border border-teal-800">
