           {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
               <PermissionsTab 
                    roles={roles}
                    permissions={permissions}
                    onAddRole={onAddRole}
                    onDeleteRole={onDeleteRole}
                    onUpdatePermission={onUpdatePermission}
                    onVerifyAdminPassword={onVerifyAdminPassword}
               />
           )}

        </div>
      </div>
    </div>
  );
};

